public String plusOut(String str, String word) {
    char[] strArray = str.toCharArray();
    int wordLen = word.length();
    for (int i = 0; i <= str.length() - wordLen; i++) {
        boolean isWord = true;
        for (int j = 0; j < wordLen; j++) {
            if (strArray[i + j] != word.charAt(j)) {
                isWord = false;
                break;
            }
        }
        if (isWord) {
