public boolean canBalance(int[] nums) {
    int total = 0;
    for(int i : nums) total += i;

    int sum = 0;
    for(int i = 0; i < nums.length; i++){
        total -= nums[i];
        if(sum == total) return true;
        sum += nums[i];
    }
    return false;
}

