public String alarmClock(int day, boolean vacation) {
    if (vacation) {
        if (day >= 1 && day <= 5) {
            return "10:00";
        } else {
            return "off";
        }
    } else {
        if (day >= 1 && day <= 5) {
            return "7:00";
        } else {
            return "10:00";
        }
    }
}

public int makeChocolate(int small, int big, int goal) {
    int bigUse = goal / 5;
    int smallUse = 0;
    if(bigUse <= big) {
        int remain = goal - bigUse * 5;
        if(remain <= small) {
            smallUse = remain;
        } else {
            smallUse = -1;
        }
    } else {
        smallUse = -1;
    }
    return smallUse;
}

