public int sum67(int[] nums)
{
    int sum = 0;
    int i = 0;
    while (i < nums.Length)
    {
        if (nums[i] == 6)
        {
            do
            {
                i++;
            } while (i < nums.Length && nums[i] != 7);
        }
        else
        {
            sum += nums[i];
            i++;
        }
    }
    return sum;
}

