            return 0;
        } else if (speed > 60 && speed <= 80) {
            return 1;
        } else {
            return 2;
        }
    }
}

public int[] fix45(int[] nums) {
    int n = nums.length;
    int j = 0;
    for (int i = 0; i < n; i++) {
        if (nums[i] != 4) {
            nums[j] = nums[i];
            j++;
        }
    }
    for (int i = n - 1; i >= 0; i--) {
        if (nums[i] == 4) {
            nums[j] = 5;
            j++;
        }
    }
    return nums;
}

