    String[] result = new String[end - start - 1];
    for (int i = 0; i < result.length; i++) {
        int number = start + i + 1;
        result[i] = (number % 3 == 0) ? ((number % 5 == 0) ? "FizzBuzz" : "Fizz") : ((number % 5 == 0) ? "Buzz" : String.valueOf(number));
    }
    return result;
}

