Code:
public boolean canBalance(int[] nums) {
    int totalSum = 0, leftSideSum = 0;
    for (int num : nums) {
        totalSum += num;
    }
    for (int num : nums) {
        if (leftSideSum == totalSum - leftSideSum - num) {
            return true;
        }
        leftSideSum += num;
    }
    return false;
}

