public int[] shiftLeft(int[] nums) {
    int[] result = new int[nums.length];
    for (int i = 0; i < nums.length; i++) {
        if (i != 0) {
            result[i - 1] = nums[i];
        } else {
            result[nums.length - 1] = nums[i];
        }
    }
    return result;
}

