    String result = "";
    int wordLen = word.length();
    int startIdx = 0;
    while (startIdx <= str.length() - wordLen) {
        int endIdx = startIdx + wordLen;
        if (str.substring(startIdx, endIdx).equals(word)) {
            result += word;
            startIdx = endIdx;
        } else {
            result += "+";
            startIdx++;
        }
    }
    for (int i = startIdx; i < str.length(); i++) {
        result += "+";
    }
    return result;
}

