public int[] fix45(int[] nums) {
    int i = 0;
    int j = nums.length - 1;
    while (i < j) {
        while (i < nums.length && nums[i] != 4) {
            i++;
        }
        while (j >= 0 && nums[j] != 5) {
            j--;
        }
        if (i < j) {
            int temp = nums[i];
            nums[i] = nums[j];
            nums[j] = temp;
            i++;
            j--;
        }
    }
    return nums;
}

