public boolean xyBalance(String str) {
    int yBalance = 0;
    for (int i = 0; i < str.length(); i++) {
        if (str.charAt(i) == 'x') {
            yBalance++;
        } else if (str.charAt(i) == 'y') {
            yBalance--;
        }
        if (yBalance > 0 && i == str.length() - 1) {
            return false;
        }
    }
    return yBalance == 0;
}

