public int sum13(int[] nums) {
    int sum = 0;
    boolean hasNext13 = false;
    for (int num : nums) {
        if (num == 13) {
            hasNext13 = true;
        } else {
            if (!hasNext13) {
                sum += num;
            }
            hasNext13 = false;
        }
    }
    return sum;
}

public int sum13(int[] nums) {
    if (nums.length == 0) {
        return 0;
    }
    int sum = 0;
    boolean hasNext13 = false;
    for (int num : nums) {
        if (num == 13) {
            hasNext13 = true;
        } else {
            if (!hasNext13) {
                sum += num;
            }
            hasNext13 = false;
        }
    }
    return sum;
}

