public int[] fix45(int[] nums) {
    int n = nums.length;
    for (int i = 0; i < n; i++) {
        if (nums[i] != 4) continue; 
        for (int j = i + 1; j < n; j++) {
            if (nums[j] == 5) {
                nums[j] = nums[j + 1];
                nums[j + 1] = 5;
                break;
            }
        }
    }
    return nums;
}

