public String alarmClock(int day, boolean vacation) {
    String alarmClock;

    if (vacation) {
        if (day >= 0 && day <= 4) {
            alarmClock = "10:00";
        } else {
            alarmClock = "off";
        }
    } else {
        if (day == 0 || day == 6) {
            alarmClock = "10:00";
        } else {
            alarmClock = "7:00";
        }
    }
    return alarmClock;
}

