public String repeatEnd(String str, int n) {
    // Handle edge case when n is 0
    if (n == 0) {
        return "";
    }

    // Get the last n characters of the string
    String ending = str.substring(str.length() - n);

    // Repeat the ending n times
    String result = "";
    for (int i = 0; i < n; i++) {
        result += ending;
    }

    return result;
}

