public int[] zeroMax(int[] nums) {
    for(int i = nums.length - 1; i >= 0; i--) {
        if(nums[i] == 0) {
            int largestOdd = findLargestOddToRight(nums, i);
            if(largestOdd != 0) {
                nums[i] = largestOdd;
            }
        }
    }
    return nums;
}

private int findLargestOddToRight(int[] nums, int startIndex) {
    int largestOdd = 0;
    for(int i = startIndex; i < nums.length; i++) {
        if(nums[i] % 2 != 0 && nums[i] > largestOdd) {
            largestOdd = nums[i];
        }
    }
    return largestOdd;
}

public int[] fix45(int[] nums) {
    int n = nums.length;
    int count = 0;
    for (int i = 0; i < n; i++) {
        if (nums[i] == 5) count++;
    }

    int[] result = new int[n];
    int j = 0;
    for (int i = 0; i < n; i++) {
        if (nums[i] == 4) {
            for (int k = j; k < n; k++) {
                if (nums[k] == 5) {
                    result[i] = 4;
                    result[i + 1] = 5;
                    i++;
                    j = k + 1;
                    count--;
                    break;
                }
            }
            if (count == 0) break;
        } else {
            result[i] = nums[i];
        }
    }
    return result;
