public static int caughtSpeeding(int speed, boolean isBirthday) {
    int speedLimit;
    if (isBirthday) {
        speedLimit = isBirthday ? 65 : 60;
    } else {
        speedLimit = 60;
    }

    if (speed <= speedLimit) {
        return 0;
