public boolean love6(int a, int b) {
    // if either a or b is 6 return true
    if (a == 6 || b == 6) {
        return true;
    }
    // if the sum or the difference of a and b is 6 return true
    if ((a + b) == 6 || Math.abs(a - b) == 6) {
        return true;
    }
    // if none of the above conditions is true return false
    return false;
}

