    int currentNumber = nums[0];
    for (int i = 1; i < nums.length; i++) {
        if (nums[i] != currentNumber) {
            currentNumber = nums[i];
            clumpCount++;
        }
    }
    return clumpCount + 1; // adding 1 because the first clump is not counted
}

