    boolean sawY = false;
    for (int i = str.length() - 1; i >= 0; i--) {
        if (str.charAt(i) == 'x') {
            if (!sawY) {
                return false;
            }
        } else if (str.charAt(i) == 'y') {
            sawY = true;
        }
    }
    return true;
}

