    a = a.toLowerCase();
    b = b.toLowerCase();

    // Check if string b is at the end of string a
    if (a.endsWith(b)) {
        return true;
    }

    // Check if string a is at the end of string b
    if (b.endsWith(a)) {
        return true;
    }

    return false;
}

