            if (result.length() != 0 && result.charAt(result.length() - 1) != 'p') {
                result.append('p');
            }
            lastWasZ = false;
        } else {
            if (lastWasZ && result.length() != 0 && result.charAt(result.length() - 1) != 'p') {
                result.append('p');
            }
            result.append(ch);
            lastWasZ = false;
        }
    }

    if (lastWasZ && result.length() != 0 && result.charAt(result.length() - 1) != 'p') {
        result.append('p');
    }

    return result.toString();
}

public int sum13(int[] nums) {
