public boolean canBalance(int[] nums) {
    int sum = 0;
    for(int num : nums) sum += num;

    if(sum % 2 != 0) return false;

    sum /= 2;
    int curSum = 0;
    for(int num : nums) {
        curSum += num;
        if(curSum == sum) return true;
    }
    return false;
}

