    boolean isFollowedBy13 = false;

    for (int num : nums) {
        if (num == 13) {
            isFollowedBy13 = true;
        } else if (!isFollowedBy13) {
            sum += num;
            isFollowedBy13 = false;
        } else {
            isFollowedBy13 = false;
        }
    }

    return sum;
}

