public int[] zeroMax(int[] nums) {
    for (int i = 0; i < nums.length; i++) {
        if (nums[i] == 0) {
            nums[i] = findMaxOdd(nums, i);
        }
    }
    return nums;
}

public int findMaxOdd(int[] nums, int startIndex) {
    int maxOdd = -1;
    for (int i = startIndex; i < nums.length; i++) {
        if (nums[i] % 2 != 0 && nums[i] > maxOdd) {
            maxOdd = nums[i];
        }
    }
    return maxOdd;
}

