public int[] fix45(int[] nums) {
    int i = 0;
    int j = 0;
    int n = nums.length;
    int[] result = new int[n];

    // copy 4's into result
    while (j < n && nums[j] != 5) {
        result[i++] = nums[j++];
    }

    // copy 5's into result, after 4's
    while (j < n && nums[j] == 5) {
        result[i++] = nums[j++];
    }

    // copy other numbers into result, after 4's and 5's
    while (j < n) {
        result[i++] = nums[j++];
    }

    return result;
}

