public int sum67(int[] nums) {
    boolean isInBetween = false;
    int sum = 0;
    for (int num : nums) {
        if (num == 6) {
            isInBetween = true;
        } else if (num == 7 && isInBetween) {
            isInBetween = false;
        } else if (!isInBetween) {
            sum += num;
        }
    }
    return sum;
}

