public String zipZap(String str) {
    int n = str.length();
    StringBuilder sb = new StringBuilder();
    for (int i = 0; i < n; i++) {
        if (i != 0 && i != n - 1 && str.charAt(i) == 'p' && str.charAt(i - 1) == 'z') {
            i++;
            while (i < n && str.charAt(i) != 'z') {
                i++;
            }
            if (i == n) {
                break;
            }
        }
        sb.append(str.charAt(i));
    }
    return sb.toString();
}

