public boolean xyBalance(String str) {
    int xPos = str.length();
    for (int i = str.length() - 1; i >= 0; i--) {
        if (str.charAt(i) == 'x') {
            xPos = i;
        } else if (str.charAt(i) == 'y' && i > xPos) {
            xPos = str.length();
        }
    }
    return xPos == str.length();
}

public int sum67(int[] nums) {
    int sum = 0;
    boolean ignoring = false;
    for (int num : nums) {
        if (num == 6) {
            ignoring = true;
        } else if (num == 7 && ignoring) {
            ignoring = false;
        } else if (!ignoring) {
            sum += num;
        }
    }
    return sum;
}

