public int sum67(int[] nums) {
    int sum = 0;
    boolean isSeeing6 = false;

    for (int num : nums) {
        if (num == 6) {
            isSeeing6 = true;
        } else if (num == 7 && isSeeing6) {
            isSeeing6 = false;
        } else if (!isSeeing6) {
            sum += num;
        }
    }

    return sum;
}

