public int[] withoutTen(int[] nums) {
    int j = 0;
    for(int i = 0; i < nums.length; i++) {
        if(nums[i] != 10) {
            nums[j] = nums[i];
            j++;
        }
    }
    while(j < nums.length) {
        nums[j] = 0;
        j++;
    }
    return nums;
}

