    int birthdayLimit = isBirthday ? 10 : 60;
    int smallTicketLimit = isBirthday ? 85 : 80;
    int bigTicketLimit = isBirthday ? 86 : 81;

    if (speed <= birthdayLimit) {
        return 0;
    } else if (speed <= smallTicketLimit) {
        return 1;
    } else {
        return 2;
    }
}

