public int sum67(int[] nums) {
    int sum = 0;
    boolean isSkipped = false;

    for (int num : nums) {
        if (num == 6) {
            isSkipped = true;
        } else if (num == 7 && isSkipped) {
            isSkipped = false;
        } else if (!isSkipped) {
            sum += num;
        }
    }

