}

public int caughtSpeeding(int speed, boolean isBirthday) {
    int birthdayAdjustedSpeed = isBirthday ? speed - 5 : speed;
    if (birthdayAdjustedSpeed <= 60) {
        return 0;
    } else if (birthdayAdjustedSpeed <= 80) {
        return 1;
    } else {
        return 2;
    }
}

